parameters.jsCode:
// Score and finalize clause anomaly results
const webhookData = $('Webhook Trigger').first().json;
const geminiResponse = $input.first().json;

let comparison = {};
try {
  const text = geminiResponse.candidates[0].content.parts[0].text;
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  comparison = JSON.parse(cleaned);
} catch (e) {
  comparison = {
    clause_comparisons: [],
    missing_clauses: [],
    added_clauses: [],
    overall_deviation_score: 0,
    risk_summary: 'Analysis failed - manual review required.'
  };
}

// Normalize all deviation scores to 0-1 range
const clauseComparisons = (comparison.clause_comparisons || []).map(clause => ({
  ...clause,
  deviation_score: Math.max(0, Math.min(1, parseFloat(clause.deviation_score) || 0))
}));

// Calculate weighted anomaly score
const deviationScores = clauseComparisons.map(c => c.deviation_score);
const avgDeviation = deviationScores.length > 0
  ? deviationScores.reduce((a, b) => a + b, 0) / deviationScores.length
  : 0;

// Factor in missing and added clauses
const missingPenalty = Math.min(0.3, (comparison.missing_clauses || []).length * 0.05);
const addedPenalty = Math.min(0.2, (comparison.added_clauses || []).length * 0.03);

const finalAnomalyScore = Math.max(0, Math.min(1, 
  Math.round((avgDeviation + missingPenalty + addedPenalty) * 100) / 100
));

// Classify anomalies by severity
const highRiskClauses = clauseComparisons.filter(c => c.deviation_score >= 0.7);
const mediumRiskClauses = clauseComparisons.filter(c => c.deviation_score >= 0.4 && c.deviation_score < 0.7);
const lowRiskClauses = clauseComparisons.filter(c => c.deviation_score > 0 && c.deviation_score < 0.4);

return [{
  json: {
    document_id: webhookData.document_id,
    entity_id: webhookData.entity_id,
    anomaly_score: finalAnomalyScore,
    anomaly_level: finalAnomalyScore >= 0.7 ? 'high' : finalAnomalyScore >= 0.4 ? 'medium' : finalAnomalyScore > 0.1 ? 'low' : 'none',
    clause_comparisons: clauseComparisons,
    missing_clauses: comparison.missing_clauses || [],
    added_clauses: comparison.added_clauses || [],
    risk_breakdown: {
      high_risk_clauses: highRiskClauses.length,
      medium_risk_clauses: mediumRiskClauses.length,
      low_risk_clauses: lowRiskClauses.length,
      standard_clauses: clauseComparisons.filter(c => c.deviation_score === 0).length
    },
    risk_summary: comparison.risk_summary || '',
    analyzed_at: new Date().toISOString()
  }
}];
